import { describe, expect, it } from "vitest";

import { diff } from "./config-sync.diff.ts";

/**
 * Golden parity with Go's `pkg/diff.Diff`. Expected outputs were generated by
 * running the Go function directly (the package ships no `_test.go`, so these
 * fixtures were captured from a throwaway test against `apps/cli-go/pkg/diff`).
 */
describe("diff", () => {
  it("returns empty string for identical input", () => {
    expect(diff("a", "same = 1\n", "b", "same = 1\n")).toBe("");
  });

  it("anchors on repeated lines (patience diff)", () => {
    expect(diff("a", "x = 1\nx = 1\nx = 1\n", "b", "x = 1\nx = 2\nx = 1\n")).toBe(
      "diff a b\n--- a\n+++ b\n@@ -1,3 +1,3 @@\n x = 1\n-x = 1\n+x = 2\n x = 1\n",
    );
  });

  it("emits the no-newline-at-end-of-file marker", () => {
    expect(diff("a", "foo = 1\nbar = 2", "b", "foo = 1\nbar = 3")).toBe(
      "diff a b\n--- a\n+++ b\n@@ -1,2 +1,2 @@\n foo = 1\n-bar = 2\n\\ No newline at end of file\n+bar = 3\n\\ No newline at end of file\n",
    );
  });

  it("renders an empty old file as 0,0", () => {
    expect(diff("a", "", "b", "added = 1\n")).toBe(
      "diff a b\n--- a\n+++ b\n@@ -0,0 +1,1 @@\n+added = 1\n",
    );
  });

  it("renders an empty new file as 0,0", () => {
    expect(diff("a", "removed = 1\n", "b", "")).toBe(
      "diff a b\n--- a\n+++ b\n@@ -1,1 +0,0 @@\n-removed = 1\n",
    );
  });
});
